// // This module implements an asynchronous reset and disable functionality for a 4-bit register.
module top_module(out, in, en, clk, rst);output reg [3:0] out;
input [3:0] in;
input en, clk, rst;

always@(posedge clk)
begin
	if(rst) out <= 4'd0;
	else
	begin
		if(en) out <= in;
	end
end

endmodule
